class Solution {
public:
    vector<int> findOrder(int numCourses, vector<vector<int>>& prerequisites) {
        vector<int> result;
        vector<int> adjList(numCourses, -1);
        for (auto prerequisite : prerequisites) {
            adjList[prerequisite[1]] = prerequisite[0];
        }
        dfs(0, adjList);
        return result;
    }

    void dfs(int course, vector<int>& adjList) {
        result.push_back(course);
        for (int neighbor : adjList[course]) {
            dfs(neighbor, adjList);
        }
    }
};
